function toStringArray(value, fallback) {
  if (!Array.isArray(value)) {
    return fallback;
  }
  const items = value
    .map((item) => (typeof item === "string" ? item.trim() : ""))
    .filter(Boolean);
  return items.length > 0 ? items : fallback;
}

function toInteger(value, fallback) {
  return Number.isInteger(value) ? value : fallback;
}

function parseConfig(raw) {
  return {
    enabledAgents: toStringArray(raw?.enabledAgents, ["main"]),
    allowedTriggers: toStringArray(raw?.allowedTriggers, ["user"]),
    simpleProvider:
      typeof raw?.simpleProvider === "string" && raw.simpleProvider.trim()
        ? raw.simpleProvider.trim()
        : "minimax-portal",
    simpleModel:
      typeof raw?.simpleModel === "string" && raw.simpleModel.trim()
        ? raw.simpleModel.trim()
        : "MiniMax-M2.7",
    maxPromptChars: toInteger(raw?.maxPromptChars, 220),
    maxLineCount: toInteger(raw?.maxLineCount, 6),
    minSimpleScore: toInteger(raw?.minSimpleScore, 3),
    debug: raw?.debug === true,
  };
}

function shouldApply(ctx, cfg) {
  if (cfg.enabledAgents.length > 0) {
    const agentId = typeof ctx?.agentId === "string" ? ctx.agentId.trim() : "";
    if (!agentId || !cfg.enabledAgents.includes(agentId)) {
      return false;
    }
  }

  if (cfg.allowedTriggers.length > 0) {
    const trigger = typeof ctx?.trigger === "string" ? ctx.trigger.trim() : "";
    if (!trigger || !cfg.allowedTriggers.includes(trigger)) {
      return false;
    }
  }

  return true;
}

function classifyPrompt(prompt, cfg) {
  const text = String(prompt ?? "").trim();
  const lowered = text.toLowerCase();
  const lineCount = text ? text.split(/\r?\n/).length : 0;

  if (!text) {
    return { simple: false, reason: "empty_prompt" };
  }
  if (text.length > cfg.maxPromptChars) {
    return { simple: false, reason: "prompt_too_long" };
  }
  if (lineCount > cfg.maxLineCount) {
    return { simple: false, reason: "too_many_lines" };
  }
  if (CONTEXT_DEPENDENT_HINTS.some((keyword) => text.includes(keyword))) {
    return { simple: false, reason: "context_dependent" };
  }
  if (BLOCK_PATTERNS.some((pattern) => pattern.test(text))) {
    return { simple: false, reason: "blocked_pattern" };
  }
  if (COMPLEX_KEYWORDS.some((keyword) => lowered.includes(keyword.toLowerCase()))) {
    return { simple: false, reason: "complex_keyword" };
  }

  let score = 0;
  const reasons = [];

  if (text.length <= Math.floor(cfg.maxPromptChars * 0.55)) {
    score += 2;
    reasons.push("very_short");
  } else {
    score += 1;
    reasons.push("short");
  }

  if (lineCount <= 2) {
    score += 1;
    reasons.push("few_lines");
  }

  if (/[?？]$/.test(text)) {
    score += 1;
    reasons.push("direct_question");
  }

  if (SIMPLE_INTENT_PATTERNS.some((pattern) => pattern.test(text))) {
    score += 2;
    reasons.push("simple_intent");
  }

  if (score >= cfg.minSimpleScore) {
    return { simple: true, reason: reasons.join("+") || "simple_score" };
  }

  return { simple: false, reason: "insufficient_simple_signal" };
}

export default function register(api) {
  const cfg = parseConfig(api.pluginConfig ?? {});
  const bind = typeof api.on === "function" ? api.on.bind(api) : api.registerHook.bind(api);

  bind(
    "before_model_resolve",
    (event, ctx) => {
      if (!shouldApply(ctx, cfg)) {
        return;
      }

      const decision = classifyPrompt(event?.prompt, cfg);
      if (!decision.simple) {
        if (cfg.debug) {
          api.logger.info?.(
            `[simple-task-router] keep_primary agent=${ctx?.agentId ?? "-"} trigger=${ctx?.trigger ?? "-"} reason=${decision.reason}`,
          );
        }
        return;
      }

      api.logger.info?.(
        `[simple-task-router] route agent=${ctx?.agentId ?? "-"} trigger=${ctx?.trigger ?? "-"} -> ${cfg.simpleProvider}/${cfg.simpleModel} reason=${decision.reason}`,
      );

      return {
        providerOverride: cfg.simpleProvider,
        modelOverride: cfg.simpleModel,
      };
    },
    { priority: 60 },
  );
}

